+    let signing_key = setup_handshake(&mut connector, &["google-ai.tuning.create"]).await;
+    let token = generate_valid_token(&signing_key, "google-ai.tuning.create");
+
+    let result = connector
+        .handle_invoke(json!({
+            "operation": "google-ai.tuning.create",
+            "input": {
